class Solution:
    def largestComponentSize(self, nums) -> int:
        from collections import Counter
        parent = list(range(max(nums) + 1))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b):
            a, b = find(a), find(b)
            if a != b:
                parent[a] = b
        def factors(n):
            f = []
            d = 2
            while d * d <= n:
                if n % d == 0:
                    f.append(d)
                    while n % d == 0:
                        n //= d
                d += 1
            if n > 1:
                f.append(n)
            return f
        for x in nums:
            for p in factors(x):
                union(x, p)
        cnt = Counter(find(x) for x in nums)
        return max(cnt.values())

