var largestComponentSize = function(nums) {
    const N = Math.max(...nums) + 1;
    const parent = Array.from({length: N}, (_, i) => i);
    function find(x) {
        while (parent[x] !== x) { parent[x] = parent[parent[x]]; x = parent[x]; }
        return x;
    }
    function union(a, b) {
        a = find(a); b = find(b);
        if (a !== b) parent[a] = b;
    }
    for (const x of nums) {
        let y = x, d = 2;
        while (d * d <= y) {
            if (y % d === 0) {
                union(x, d);
                while (y % d === 0) y = Math.floor(y / d);
            }
            d++;
        }
        if (y > 1) union(x, y);
    }
    const cnt = new Map();
    for (const x of nums) {
        const r = find(x);
        cnt.set(r, (cnt.get(r) || 0) + 1);
    }
    return Math.max(...cnt.values());
};
